+                    schema::migrate_metadata_schema(db.as_ref())
+                        .await
+                        .map_err(ApiError::internal)?;
+                    ensure_metadata_lock_row(db.as_ref())
+                        .await
+                        .map_err(ApiError::internal)?;
+                    seed_catalog(db.as_ref(), catalog).await
+                })
+            }
+            MetadataStoreInner::Memory(memory) => {
+                *memory
+                    .catalog
