    pub async fn mutate_repository<R, F>(
        &self,
        owner: &str,
        name: &str,
        op: F,
    ) -> Result<R, ApiError>
    where
        R: Send + 'static,
        F: FnOnce(&mut StoredRepository) -> Result<RepositoryMutation<R>, ApiError>
            + Send
            + 'static,
