pub async fn save_repository_delta<C>(
    conn: &C,
    before: &StoredRepository,
    after: &StoredRepository,
) -> Result<(), ApiError>
where
    C: ConnectionTrait,
{
    if before.record.id != after.record.id {
        return Err(ApiError::internal_message(
            "repository mutation cannot change repository identity",
        ));
    }

    let row = entities::repository::Model::from_domain(after)?;
    let mut active = row.clone().into_active_model();
    let mut row_changed = false;
    macro_rules! set_if_changed {
        ($field:ident, $before:expr, $after:expr) => {
            if $before != $after {
                active.$field = Set(row.$field.clone());
                row_changed = true;
            }
        };
    }
    set_if_changed!(
        owner_handle,
        before.record.owner_handle,
        after.record.owner_handle
    );
    set_if_changed!(name, before.record.name, after.record.name);
    set_if_changed!(
        owner_user_id,
        before.record.owner_user_id,
        after.record.owner_user_id
    );
    set_if_changed!(
        publication_state,
        before.record.publication_state,
        after.record.publication_state
    );
    set_if_changed!(
        default_visibility,
        before.record.default_visibility,
        after.record.default_visibility
    );
    set_if_changed!(
        change_version,
        before.record.change_version,
        after.record.change_version
    );
    set_if_changed!(repo_config, before.repo_config, after.repo_config);
    set_if_changed!(policy, before.policy, after.policy);
    set_if_changed!(graph, before.graph, after.graph);
    set_if_changed!(
        visibility_events,
        before.visibility_events,
        after.visibility_events
    );
    if row_changed {
        active.update(conn).await.map_err(ApiError::internal)?;
    }

    save_repository_fact_delta(conn, before, after).await?;
    save_repository_relation_delta(conn, before, after).await?;
    enqueue_projection_read_model_rebuild(conn, after).await?;
    Ok(())
}

